import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return base premium plus processing fee for a single sword", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(115);
    });
    it("should return base premium plus processing fee for a single amulet", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(71);
    });
    it("should return base premium plus processing fee for a single component", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune", material: "stone", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(33);
    });
    it.todo("should apply bundle premium for 3 alike components");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 15% discount for contracts after the first");
  });

  describe("claim", () => {
    it.todo("should apply 100 G deductible to a basic damage claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse 50% of damage for high enchantment items (enchantment >= 8)");
    it.todo("should fully reimburse damage for dragon material items");
  });
});

